    "line_item_mismatch",
    "hallucination_relative_to_gold",
    "missing_item",
    "formatting_mismatch"
  ],
  "field_notes": {
    "company": "The model corrected a typo ('Freindly' to 'Friendly') found in the gold label.",
    "date": "The date format differs from the gold label (MM/DD/YYYY vs YYYY-MM-DD).",
    "address": "The predicted address includes a phone number not present in the gold address field.",
    "subtotal": "The predicted subtotal is missing the trailing zero ('71.4' vs '71.40').",
    "line_items": "The model extracted 'Patron Silver', which is on the receipt but absent from the gold line items. It also failed to extract both 'Chicken Caprese' entries (one misspelled in gold) that were required by the gold labels."
  }
}
